SELECT SUM(guaranteed_amount) AS total_guaranteed_amount
FROM contracts
WHERE player_id = 0;

SELECT SUM(c.salary) AS total_salary
FROM contracts c
WHERE c.start_date < '2022-01-01' AND c.end_date > '2022-01-01';

SELECT SUM(remaining_cap_space) AS total_remaining_cap
FROM salary_cap
WHERE team_id = 1;

SELECT used_cap
FROM salary_cap
WHERE team_id = 0 AND year = 2023;

SELECT player_id, injury_type, injury_date, return_date
FROM players_injury_history
WHERE injury_type = 'Hamstring';
